# Generated by Codex for Pyomo DoE PDE discretization scaling analysis
"""
Parse PDE discretization JSON diagnostics, archive prior artifacts safely,
produce grouped-bar visualizations, and write a scaling table and summary.
"""

from __future__ import annotations

import json
import shutil
import time
from datetime import datetime
from pathlib import Path
from typing import Dict, Iterable, List, Tuple

import matplotlib.pyplot as plt
import numpy as np
import pandas as pd


ROOT_DIR = Path("/Users/snarasi2/projects/Pyomo_DoE_CRC/out")
TIMESTAMP = datetime.now().strftime("%Y%m%d_%H%M%S")
ANALYSIS_DIR = ROOT_DIR / f"analysis_{TIMESTAMP}"
ARCHIVE_DIR = ROOT_DIR / f"archive_{TIMESTAMP}"

TIME_METRICS = [
    "doe_build_time",
    "doe_init_time",
    "doe_solve_time",
    "doe_wall_time",
]

SOLVER_METRICS = [
    "ipopt_iters",
    "obj_eval",
    "grad_eval",
    "eq_con_eval",
    "eq_jac_eval",
    "hess_eval",
]

ALL_METRICS = TIME_METRICS + SOLVER_METRICS + [
    "ipopt_cpu_wo_feval",
    "ipopt_cpu_nlp_feval",
    "ipopt_exit",
]


def ensure_directories() -> None:
    """
    Create analysis and archive directories for this run.
    """
    ANALYSIS_DIR.mkdir(parents=True, exist_ok=True)
    ARCHIVE_DIR.mkdir(parents=True, exist_ok=True)


def _is_recent(path: Path, seconds: int) -> bool:
    """
    Check if a file was modified within the last N seconds.

    Parameters:
        path: File path.
        seconds: Age threshold in seconds.

    Returns:
        True if modified within the threshold.
    """
    try:
        return (time.time() - path.stat().st_mtime) <= seconds
    except OSError:
        return False


def _is_generated_name(name: str) -> bool:
    """
    Heuristic check for generated artifact names.

    Parameters:
        name: File name.

    Returns:
        True if the name looks like a generated artifact.
    """
    lowered = name.lower()
    keywords = [
        "pde",
        "doe",
        "diagnostic",
        "scaling",
        "metrics",
        "summary",
        "analysis",
        "plot",
    ]
    return any(keyword in lowered for keyword in keywords)


def archive_prior_artifacts(root_dir: Path, archive_dir: Path) -> List[Tuple[Path, Path]]:
    """
    Move prior generated artifacts from the root output directory to archive.

    Parameters:
        root_dir: Root output directory.
        archive_dir: Archive directory for this run.

    Returns:
        List of (source, destination) moves performed.
    """
    candidates: List[Tuple[Path, Path]] = []
    if not root_dir.exists():
        print(f"WARNING: Root directory not found: {root_dir}")
        return candidates

    for entry in root_dir.iterdir():
        if entry.is_dir():
            continue
        if entry.suffix.lower() not in {".png", ".csv", ".txt"}:
            continue
        if entry.suffix.lower() == ".json":
            continue
        if entry.name.lower().startswith("readme"):
            continue

        recent = _is_recent(entry, 24 * 60 * 60)
        generated = _is_generated_name(entry.name)
        if recent or generated:
            destination = archive_dir / entry.name
            candidates.append((entry, destination))

    if not candidates:
        print("no prior artifacts found.")
        return candidates

    print("Archiving prior artifacts:")
    for src, dst in candidates:
        print(f"- {src} -> {dst}")

    moved: List[Tuple[Path, Path]] = []
    for src, dst in candidates:
        try:
            shutil.move(str(src), str(dst))
            moved.append((src, dst))
        except OSError as exc:
            print(f"WARNING: Failed to move {src}: {exc}")

    print(f"Moved {len(moved)} file(s) to archive.")
    return moved


def discover_case_dirs(root_dir: Path) -> List[Path]:
    """
    Find case directories matching case_*_nfe_x*_nfe_t*.

    Parameters:
        root_dir: Root directory containing case folders.

    Returns:
        List of case directory paths.
    """
    if not root_dir.exists():
        raise SystemExit(f"ERROR: Root directory not found: {root_dir}")

    case_dirs = [
        path for path in root_dir.iterdir()
        if path.is_dir() and path.name.startswith("case_") and "nfe_x" in path.name
    ]
    if not case_dirs:
        raise SystemExit(f"ERROR: No case folders found in {root_dir}")
    return case_dirs


def parse_case_name(case_dir: Path) -> Tuple[int, int]:
    """
    Extract nfe_x and nfe_t from a case directory name.

    Parameters:
        case_dir: Case directory path.

    Returns:
        Tuple of (nfe_x, nfe_t).
    """
    name = case_dir.name
    if "nfe_x" not in name or "nfe_t" not in name:
        raise SystemExit(f"ERROR: Failed to parse nfe_x/nfe_t from {name}")
    nfe_x = int(name.split("nfe_x")[1].split("_")[0])
    nfe_t = int(name.split("nfe_t")[1].split("_")[0])
    return nfe_x, nfe_t


def find_method_json(case_dir: Path, method_name: str) -> Path:
    """
    Locate the JSON file for a given method within a case directory.

    Parameters:
        case_dir: Case directory path.
        method_name: Method folder name (central or symbolic).

    Returns:
        Path to the JSON file.
    """
    candidates = [
        d for d in case_dir.iterdir()
        if d.is_dir() and d.name.lower() == method_name
    ]
    if not candidates:
        raise SystemExit(f"ERROR: Missing method folder '{method_name}' in {case_dir}")
    method_dir = candidates[0]
    json_files = list(method_dir.glob("*.json"))
    if not json_files:
        raise SystemExit(f"ERROR: No JSON files in {method_dir}")
    return json_files[0]


def load_json(path: Path) -> Dict[str, object]:
    """
    Load a JSON file to a dictionary.

    Parameters:
        path: JSON file path.

    Returns:
        Dictionary of JSON contents.
    """
    try:
        with path.open("r", encoding="utf-8") as handle:
            return json.load(handle)
    except UnicodeDecodeError:
        with path.open("r", encoding="latin1") as handle:
            return json.load(handle)


def build_table(case_dirs: Iterable[Path]) -> pd.DataFrame:
    """
    Build a dataframe with one row per (case, method).

    Parameters:
        case_dirs: Iterable of case directory paths.

    Returns:
        Dataframe containing identifiers and metrics.
    """
    rows: List[Dict[str, object]] = []
    for case_dir in case_dirs:
        nfe_x, nfe_t = parse_case_name(case_dir)
        for method in ["central", "symbolic"]:
            json_path = find_method_json(case_dir, method)
            payload = load_json(json_path)
            row: Dict[str, object] = {
                "case_folder": case_dir.name,
                "method": method.capitalize(),
                "nfe_x": nfe_x,
                "nfe_t": nfe_t,
            }
            for metric in ALL_METRICS:
                row[metric] = payload.get(metric)
            rows.append(row)
    df = pd.DataFrame(rows)
    df = df.sort_values(by=["nfe_x", "nfe_t", "method"], kind="stable").reset_index(drop=True)
    return df


def add_ratio_columns(df: pd.DataFrame) -> pd.DataFrame:
    """
    Add symbolic/central ratios for each metric by case.

    Parameters:
        df: Base dataframe with one row per (case, method).

    Returns:
        Dataframe with added ratio columns.
    """
    ratios: List[Dict[str, object]] = []
    for (case_folder, nfe_x, nfe_t), group in df.groupby(
        ["case_folder", "nfe_x", "nfe_t"], sort=False
    ):
        central = group[group["method"] == "Central"]
        symbolic = group[group["method"] == "Symbolic"]
        if central.empty or symbolic.empty:
            continue
        ratio_row: Dict[str, object] = {
            "case_folder": case_folder,
            "nfe_x": nfe_x,
            "nfe_t": nfe_t,
        }
        for metric in ALL_METRICS:
            c_val = central.iloc[0][metric]
            s_val = symbolic.iloc[0][metric]
            ratio = np.nan
            if c_val not in (None, 0) and s_val is not None:
                try:
                    ratio = float(s_val) / float(c_val)
                except (TypeError, ValueError, ZeroDivisionError):
                    ratio = np.nan
            ratio_row[f"{metric}_ratio"] = ratio
        ratios.append(ratio_row)

    ratio_df = pd.DataFrame(ratios)
    merged = pd.merge(
        df,
        ratio_df,
        on=["case_folder", "nfe_x", "nfe_t"],
        how="left",
    )
    return merged


def format_xtick_labels(case_order: pd.DataFrame) -> List[str]:
    """
    Build categorical x-axis labels from nfe_x and nfe_t.

    Parameters:
        case_order: Dataframe with nfe_x and nfe_t columns.

    Returns:
        List of labels like "x2t2".
    """
    labels = []
    for nfe_x, nfe_t in case_order[["nfe_x", "nfe_t"]].values:
        labels.append(f"x{int(nfe_x)}t{int(nfe_t)}")
    return labels


def _metric_series(
    ordered: pd.DataFrame, case_order: pd.DataFrame, metric: str, method: str
) -> List[float]:
    """
    Build a series of metric values aligned to the discretization order.

    Parameters:
        ordered: Ordered dataframe.
        case_order: Distinct (nfe_x, nfe_t) rows in order.
        metric: Metric name.
        method: Method name (Central/Symbolic).

    Returns:
        List of metric values aligned to case_order.
    """
    subset = ordered[ordered["method"] == method]
    series = subset.set_index(["nfe_x", "nfe_t"])[metric]
    values = [series.get((row.nfe_x, row.nfe_t), np.nan) for row in case_order.itertuples()]
    return values


def plot_metric_blocks(
    df: pd.DataFrame,
    metrics: List[str],
    metric_labels: Dict[str, str],
    output_path: Path,
    title: str,
    x_label: str,
) -> Path:
    """
    Plot metric-by-discretization blocks as horizontal paired bars.

    Parameters:
        df: Input dataframe.
        metrics: Metrics to plot in order.
        metric_labels: Mapping from metric to display label.
        output_path: Destination PNG path.
        title: Figure title.
        x_label: X-axis label.

    Returns:
        Path to the saved plot file.
    """
    ordered = df.sort_values(by=["nfe_x", "nfe_t", "method"], kind="stable")
    case_order = ordered[["nfe_x", "nfe_t"]].drop_duplicates()
    discretization_labels = [
        f"nfe_x = {int(row.nfe_x)}, nfe_t = {int(row.nfe_t)}"
        for row in case_order.itertuples()
    ]

    num_cases = len(case_order)
    block_gap = 1.5
    row_positions: List[float] = []
    metric_centers: List[float] = []

    for metric_index in range(len(metrics)):
        block_start = metric_index * (num_cases + block_gap)
        for case_index in range(num_cases):
            row_positions.append(block_start + case_index)
        metric_centers.append(block_start + (num_cases - 1) / 2)

    fig, ax = plt.subplots(figsize=(14, max(6, len(metrics) * 1.4)))

    central_color = "white"
    symbolic_color = "lightgrey"
    bar_height = 0.35
    offset = bar_height / 2 + 0.02

    for metric_index, metric in enumerate(metrics):
        block_start = metric_index * (num_cases + block_gap)
        for case_index, case_row in enumerate(case_order.itertuples()):
            base_y = block_start + case_index
            central_val = _metric_series(ordered, case_order, metric, "Central")[case_index]
            symbolic_val = _metric_series(ordered, case_order, metric, "Symbolic")[case_index]
            ax.barh(
                base_y - offset,
                central_val,
                height=bar_height,
                color=central_color,
                edgecolor="black",
                linewidth=1.5,
                alpha=1.0,
            )
            ax.barh(
                base_y + offset,
                symbolic_val,
                height=bar_height,
                color=symbolic_color,
                edgecolor="black",
                linewidth=1.5,
                alpha=1.0,
            )

    ax.set_yticks(metric_centers)
    ax.set_yticklabels([metric_labels.get(m, m) for m in metrics])
    ax.set_xlabel(x_label)
    ax.set_title(title)
    ax.grid(axis="x", linestyle="--", alpha=0.3)

    right_axis = ax.twinx()
    right_axis.set_ylim(ax.get_ylim())
    right_axis.set_yticks(row_positions)
    right_axis.set_yticklabels(
        discretization_labels * len(metrics),
        rotation=0,
    )
    right_axis.tick_params(axis="y", length=0)

    legend_handles = [
        plt.Rectangle((0, 0), 1, 1, facecolor=central_color, edgecolor="black", linewidth=1.5),
        plt.Rectangle((0, 0), 1, 1, facecolor=symbolic_color, edgecolor="black", linewidth=1.5),
    ]
    ax.legend(
        legend_handles,
        ["Central finite difference", "Symbolic"],
        loc="upper right",
    )

    fig.tight_layout()
    fig.savefig(output_path, dpi=150)
    plt.close(fig)
    return output_path


def plot_time_metrics(df: pd.DataFrame, output_dir: Path) -> Path:
    """
    Plot time metrics as grouped bars in two subplots.

    Parameters:
        df: Input dataframe.
        output_dir: Output directory for the PNG.

    Returns:
        Path to the saved plot file.
    """
    legend_labels = {
        "doe_build_time": "Build",
        "doe_init_time": "Init",
        "doe_solve_time": "Solve",
        "doe_wall_time": "Wall",
    }
    output_path = output_dir / "pde_time_metrics_vs_discretization.png"
    return plot_metric_blocks(
        df,
        TIME_METRICS,
        legend_labels,
        output_path,
        "Time metrics vs discretization (Central FD vs Symbolic)",
        "Time (seconds)",
    )


def plot_solver_metrics(df: pd.DataFrame, output_dir: Path) -> Path:
    """
    Plot solver metrics as grouped bars with Central/Symbolic pairing.

    Parameters:
        df: Input dataframe.
        output_dir: Output directory for the PNG.

    Returns:
        Path to the saved plot file.
    """
    legend_labels = {
        "ipopt_iters": "Iters",
        "obj_eval": "Obj",
        "grad_eval": "Grad",
        "eq_con_eval": "EqCon",
        "eq_jac_eval": "EqJac",
        "hess_eval": "Hess",
    }
    output_path = output_dir / "pde_solver_metrics_vs_discretization.png"
    return plot_metric_blocks(
        df,
        SOLVER_METRICS,
        legend_labels,
        output_path,
        "Solver metrics vs discretization (Central FD vs Symbolic)",
        "Count",
    )


def write_summary(df: pd.DataFrame, output_path: Path) -> None:
    """
    Write a quantitative summary of scaling behavior.

    Parameters:
        df: Dataframe with metrics and ratios.
        output_path: Path for the summary text file.
    """
    lines: List[str] = []
    ordered = df.sort_values(by=["nfe_x", "nfe_t", "method"], kind="stable")
    case_order = ordered[["nfe_x", "nfe_t"]].drop_duplicates()
    case_groups = ordered.groupby(["nfe_x", "nfe_t"], sort=False)

    lines.append("PDE discretization scaling summary")
    lines.append("Figures:")
    lines.append("1) pde_time_metrics_vs_discretization.png")
    lines.append("2) pde_solver_metrics_vs_discretization.png")
    lines.append("")

    for (nfe_x, nfe_t), group in case_groups:
        label = f"x{int(nfe_x)}t{int(nfe_t)}"
        lines.append(f"Case {label}")
        for method in ["Central", "Symbolic"]:
            row = group[group["method"] == method]
            if row.empty:
                continue
            build = row.iloc[0]["doe_build_time"]
            solve = row.iloc[0]["doe_solve_time"]
            wall = row.iloc[0]["doe_wall_time"]
            ipopt_exit = row.iloc[0]["ipopt_exit"]
            lines.append(
                f"{method}: build={build}, solve={solve}, wall={wall}, ipopt_exit={ipopt_exit}"
            )

        ratio_row = group[group["method"] == "Symbolic"]
        if not ratio_row.empty:
            build_ratio = ratio_row.iloc[0].get("doe_build_time_ratio")
            solve_ratio = ratio_row.iloc[0].get("doe_solve_time_ratio")
            wall_ratio = ratio_row.iloc[0].get("doe_wall_time_ratio")
            lines.append(
                f"Ratios (symbolic/central): build={build_ratio}, solve={solve_ratio}, wall={wall_ratio}"
            )

        central_row = group[group["method"] == "Central"]
        if not central_row.empty:
            build = central_row.iloc[0]["doe_build_time"]
            solve = central_row.iloc[0]["doe_solve_time"]
            wall = central_row.iloc[0]["doe_wall_time"]
            if build is not None and solve is not None and wall is not None:
                dominant = "build" if build >= solve else "solve"
                lines.append(
                    f"Dominant wall contributor (Central): {dominant} (build={build}, solve={solve}, wall={wall})"
                )

        anomalies = []
        for _, row in group.iterrows():
            ipopt_exit = row.get("ipopt_exit")
            if ipopt_exit not in (None, 0, "optimal", "Optimal"):
                anomalies.append(f"{row['method']} ipopt_exit={ipopt_exit} (non-optimal)")
        if anomalies:
            lines.append("Anomalies: " + "; ".join(anomalies))
        lines.append("")

    lines.append("Scaling progression by discretization:")
    for method in ["Central", "Symbolic"]:
        subset = ordered[ordered["method"] == method]
        build_seq = []
        solve_seq = []
        wall_seq = []
        for row in case_order.itertuples():
            row_data = subset[(subset["nfe_x"] == row.nfe_x) & (subset["nfe_t"] == row.nfe_t)]
            if row_data.empty:
                continue
            build_seq.append(row_data.iloc[0]["doe_build_time"])
            solve_seq.append(row_data.iloc[0]["doe_solve_time"])
            wall_seq.append(row_data.iloc[0]["doe_wall_time"])
        lines.append(f"{method} build times: {build_seq}")
        lines.append(f"{method} solve times: {solve_seq}")
        lines.append(f"{method} wall times: {wall_seq}")

    output_path.write_text("\n".join(lines) + "\n", encoding="utf-8")


def write_manifest(paths: List[Path], output_path: Path) -> None:
    """
    Write a manifest listing all output files created in this run.

    Parameters:
        paths: List of output paths.
        output_path: Manifest path.
    """
    lines = [str(path) for path in paths]
    output_path.write_text("\n".join(lines) + "\n", encoding="utf-8")


def main() -> None:
    """
    Entry point for scaling analysis from JSON diagnostics.
    """
    ensure_directories()
    archive_prior_artifacts(ROOT_DIR, ARCHIVE_DIR)

    case_dirs = discover_case_dirs(ROOT_DIR)
    df = build_table(case_dirs)
    df = add_ratio_columns(df)

    output_table = ANALYSIS_DIR / "pde_scaling_table.csv"
    df.to_csv(output_table, index=False)

    time_plot = plot_time_metrics(df, ANALYSIS_DIR)
    solver_plot = plot_solver_metrics(df, ANALYSIS_DIR)

    summary_path = ANALYSIS_DIR / "pde_scaling_summary.txt"
    write_summary(df, summary_path)

    manifest_path = ANALYSIS_DIR / "manifest_outputs.txt"
    write_manifest(
        [output_table, time_plot, solver_plot, summary_path, manifest_path],
        manifest_path,
    )

    print(f"Wrote table: {output_table}")
    print(f"Wrote summary: {summary_path}")
    print(f"Wrote plots: {time_plot} and {solver_plot}")
    print(f"Wrote manifest: {manifest_path}")


if __name__ == "__main__":
    main()
